return ['domain'=>NULL,'plural-forms'=>'nplurals=1; plural=0;','language'=>'id_ID','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Harap perbarui plugin TranslatePress - Multilingual ke versi %1$s atau lebih tinggi untuk memastikan %2$s berfungsi dengan benar.','Please install and activate the TranslatePress - Multilingual plugin'=>'Harap instal dan aktifkan plugin TranslatePress - Multilingual','Install & Activate'=>'Instal & Aktifkan','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Harap perbarui TranslatePress - Multilingual ke versi %2$s atau lebih baru. Versi TranslatePress - Multilingual yang terpasang saat ini tidak lagi kompatibel dengan versi %1$s saat ini.','All TranslatePress functionalities are disabled until then.'=>'Semua fungsionalitas TranslatePress dinonaktifkan hingga saat itu.','Update Now'=>'Perbarui Sekarang','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Add-on TranslatePress ini telah dimigrasikan ke plugin utama dan tidak lagi digunakan. Anda dapat menghapusnya.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> memerlukan setidaknya versi PHP 5.6.20+ untuk berjalan. Ini adalah <a href="%s">persyaratan minimum versi WordPress terbaru</a>. Harap hubungi administrator server Anda untuk memperbarui versi PHP Anda.','Advanced'=>'Lanjutan','Settings saved.'=>'Pengaturan disimpan.','Are you sure you want to remove this item?'=>'Apakah Anda yakin ingin menghapus item ini?','Remove'=>'Hapus','Add'=>'Tambah','Select...'=>'Pilih...','[%s] Low TranslatePress AI Words'=>'[%s] Kata TranslatePress AI Hampir Habis','upgrade your plan or get extra AI Words'=>'tingkatkan paket Anda atau dapatkan kata AI tambahan','upgrade your plan'=>'tingkatkan paket Anda','TranslatePress AI words are running low on your site.'=>'Kata TranslatePress AI di situs Anda hampir habis.','Current status: %s words remaining'=>'Status saat ini: %s kata tersisa','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Setelah kata AI yang tersisa habis, terjemahan otomatis melalui TranslatePress AI akan dijeda.','To continue translating your content, please %1$s over at %2$s'=>'Untuk melanjutkan penerjemahan konten Anda, silakan %1$s di %2$s','Manage Notification: %s'=>'Kelola Notifikasi: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Tersedia versi baru %1$s. %2$sLihat detail versi %3$s%4$s atau %5$sperbarui sekarang%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Tersedia versi baru %1$s. %2$sLihat detail versi %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Untuk mengaktifkan pembaruan, silakan %1$smasukkan kunci lisensi Anda%2$s. Butuh kunci lisensi? %3$sBeli sekarang%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Untuk mengaktifkan pembaruan, silakan buka %1$shalaman lisensi%2$s dan periksa bahwa Anda memiliki lisensi yang valid.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Untuk mengaktifkan pembaruan, lisensi Anda perlu diperpanjang. Silakan buka halaman %1$sTranslatePress Account%2$s dan masuk untuk memperpanjang.','You do not have permission to install plugin updates'=>'Anda tidak memiliki izin untuk memasang pembaruan plugin','Error'=>'Kesalahan','Your TranslatePress license key is invalid or missing.'=>'Kunci lisensi TranslatePress Anda tidak valid atau hilang.','Your license key expired on %s.'=>'Kunci lisensi Anda kedaluwarsa pada %s.','Your license key has been disabled.'=>'Kunci lisensi Anda telah dinonaktifkan.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Kunci lisensi Anda dinonaktifkan untuk URL ini. Aktifkan kembali dari <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Kelola Situs.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Kunci lisensi tidak cocok.</strong> Lisensi yang Anda masukkan tidak cocok dengan versi TranslatePress yang telah Anda pasang.</p><p>Silakan periksa bahwa Anda telah memasang versi yang benar untuk lisensi Anda dari akun TranslatePress Anda.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Jika Anda hanya memasang plugin gratis tetapi menambahkan lisensi berbayar, silakan pasang plugin berbayar dari akun TranslatePress Anda.','Your license key has reached its activation limit.'=>'Kunci lisensi Anda telah mencapai batas aktivasi.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Tingkatkan paket Anda untuk menambahkan lebih banyak situs. %1$sTingkatkan sekarang%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Situs web ini sudah diaktifkan dengan lisensi gratis. Setiap situs web hanya dapat menggunakan satu lisensi gratis.','An error occurred, please try again.'=>'Terjadi kesalahan, silakan coba lagi.','You have successfully activated your license'=>'Anda telah berhasil mengaktifkan lisensi Anda','Others'=>'Lainnya','Restrict by Language'=>'Batasi berdasarkan bahasa','Exclude from Language'=>'Kecualikan dari bahasa','Restrict element to language'=>'Batasi elemen ke bahasa','Show this element only in one language.'=>'Tampilkan elemen ini hanya dalam satu bahasa.','Enable translation'=>'Aktifkan terjemahan','Allow translation to the corresponding language only if the content is written in the default language.'=>'Izinkan terjemahan ke bahasa yang sesuai hanya jika konten ditulis dalam bahasa default.','Select language'=>'Pilih bahasa','Choose in which language to show this element.'=>'Pilih bahasa untuk menampilkan elemen ini.','Exclude element from language'=>'Kecualikan elemen dari bahasa','Exclude this element from specific languages.'=>'Kecualikan elemen ini dari bahasa tertentu.','Select languages'=>'Pilih bahasa','Choose from which languages to exclude this element.'=>'Pilih bahasa untuk mengecualikan elemen ini.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Elemen ini akan tetap terlihat saat Anda menerjemahkan situs web melalui Editor Terjemahan.','The content of this element should be written in the default language.'=>'Konten elemen ini harus ditulis dalam bahasa default.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> mengalami kesalahan SQL. <a href="%s" title="Lihat Kesalahan SQL TranslatePress">Periksa kesalahannya</a>.','Automatic translation has been disabled.'=>'Terjemahan otomatis telah dinonaktifkan.','Dismiss this notice.'=>'Tutup pemberitahuan ini.','Logged errors'=>'Kesalahan yang tercatat','These are the most recent 5 errors logged by TranslatePress:'=>'Berikut adalah 5 kesalahan terbaru yang dicatat oleh TranslatePress:','Yes'=>'Ya','Why are these errors occuring'=>'Mengapa kesalahan ini terjadi','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Jika TranslatePress mendeteksi ada yang salah saat menjalankan kueri pada database Anda, fitur Terjemahan Otomatis mungkin dinonaktifkan untuk menghindari biaya tambahan dari Google/DeepL. Terjemahan Otomatis perlu diaktifkan secara manual setelah Anda menyelesaikan masalahnya.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Kesalahan SQL yang terdeteksi dapat terjadi karena berbagai alasan, termasuk tabel yang tidak ada, kurangnya izin bagi pengguna SQL untuk membuat tabel atau melakukan operasi lain, masalah setelah migrasi situs, atau perubahan konfigurasi server SQL.','What you can do in this situation'=>'Apa yang dapat Anda lakukan dalam situasi ini','Plan A.'=>'Rencana A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Buka Pengaturan -> TranslatePress -> tab Umum dan Simpan Pengaturan. Ini akan meregenerasi tabel menggunakan pengaturan SQL Anda saat ini. Periksa apakah tidak ada lagi kesalahan yang terjadi saat menjelajahi situs web Anda dalam bahasa terjemahan. Lihat stempel waktu kesalahan untuk memastikan Anda tidak melihat kesalahan lama. Hanya 5 kesalahan terbaru yang ditampilkan.','Plan B.'=>'Rencana B.','If your problem isn\'t solved, try the following steps:'=>'Jika masalah Anda belum teratasi, coba langkah-langkah berikut:','Create a backup of your database'=>'Buat cadangan database Anda','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Buat salinan setiap tabel terjemahan yang mengalami kesalahan. Anda dapat menyalin tabel dalam database yang sama (misalnya trp_dictionary_en_us_es_es_COPY) -- lakukan langkah ini hanya jika Anda ingin menyimpan terjemahan saat ini.','Remove the trouble tables by executing the DROP function on them'=>'Hapus tabel yang bermasalah dengan menjalankan fungsi DROP pada tabel tersebut','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Buka Pengaturan -> TranslatePress -> tab Umum dan Simpan Pengaturan. Ini akan meregenerasi tabel menggunakan server SQL Anda saat ini.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Salin konten yang relevan dari tabel yang diduplikasi (misalnya trp_dictionary_en_us_es_es_COPY) ke tabel yang baru dibuat (trp_dictionary_en_us_es_es) -- lakukan langkah ini hanya jika Anda ingin menyimpan terjemahan saat ini.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Uji untuk melihat apakah semuanya berfungsi. Jika terjadi masalah, Anda dapat memulihkan cadangan yang telah Anda buat di langkah pertama. Periksa apakah tidak ada lagi kesalahan yang terjadi saat menjelajahi situs web Anda dalam bahasa terjemahan. Lihat stempel waktu kesalahan untuk memastikan Anda tidak melihat kesalahan lama. Hanya 5 kesalahan terbaru yang ditampilkan.','Plan C.'=>'Rencana C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Jika masalah Anda masih belum teratasi, coba tanyakan kepada penyedia hosting Anda tentang kesalahan tersebut. Masalah yang paling umum adalah kurangnya izin bagi pengguna SQL, seperti izin Create Tables.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Tidak dapat menginstal. Coba lagi dari <a href="%s" >Dasbor Plugin.</a>','Active'=>'Aktif','Permission denied.'=>'Izin ditolak.','Invalid nonce.'=>'Nonce tidak valid.','Settings scope unknown.'=>'Cakupan pengaturan tidak diketahui.','Legacy disabled.'=>'Legacy dinonaktifkan.','Language Switcher'=>'Pengalih Bahasa','Change language to %s'=>'Ubah bahasa ke %s','Automatic Translation'=>'Terjemahan Otomatis','DeepL'=>'DeepL','Unsupported languages'=>'Bahasa yang tidak didukung','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Mesin terjemahan otomatis yang dipilih tidak menyediakan dukungan untuk bahasa-bahasa ini.<br>Anda masih dapat menerjemahkan halaman dalam bahasa-bahasa ini secara manual menggunakan Editor Terjemahan.','API key validation failed.'=>'Validasi kunci API gagal.','API key verification was successful.'=>'Verifikasi kunci API berhasil.','Please enter your Google Translate key.'=>'Silakan masukkan kunci Google Translate Anda.','Please enter your DeepL API key.'=>'Silakan masukkan kunci API DeepL Anda.','Not TranslatePress onboarding page.'=>'Bukan halaman orientasi TranslatePress.','Step %s does not exist'=>'Langkah %s tidak ada','Welcome'=>'Selamat Datang','Add Languages'=>'Tambah Bahasa','Enable Addons'=>'Aktifkan Pengaya','Finalize'=>'Selesaikan','Exit Setup'=>'Keluar dari Penyiapan','Upgrade'=>'Tingkatkan','Nothing here'=>'Tidak ada apa pun di sini','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Lisensi <strong>TranslatePress</strong> Anda hilang atau tidak valid. <br/>Silakan %1$sdaftarkan salinan Anda%2$s untuk mengaktifkan terjemahan situs web otomatis via TranslatePress AI, addon premium, pembaruan otomatis, dan dukungan. Butuh kunci lisensi? %3$sBeli sekarang%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Lisensi <strong>TranslatePress</strong> Anda akan berakhir pada %1$s. Silakan %2$sPerpanjang Lisensi Anda%3$s untuk terus mendapatkan akses ke terjemahan otomatis via TP AI, addon premium, unduhan produk, dan pembaruan otomatis. %4$sPerpanjang Sekarang%5$s','Error: '=>'Kesalahan: ','Something went wrong, please try again.'=>'Terjadi kesalahan, silakan coba lagi.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Lisensi <strong>TranslatePress</strong> Anda telah berakhir. <br/>Silakan %1$sPerpanjang Lisensi Anda%2$s untuk terus mendapatkan akses ke terjemahan otomatis via TranslatePress AI, addon premium, unduhan produk, dan pembaruan otomatis. %3$sPerpanjang sekarang %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Kunci lisensi tidak cocok. Lisensi yang Anda masukkan tidak cocok dengan versi <strong>%1$s</strong> yang telah Anda instal. <br/>Silakan periksa bahwa Anda telah menginstal versi yang benar untuk lisensi Anda dari %2$sakun TranslatePress%3$s Anda.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Jika Anda hanya menginstal plugin gratis tetapi menambahkan lisensi berbayar, silakan instal plugin berbayar dari akun TranslatePress Anda.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Anda telah mencapai batas aktivasi untuk lisensi <strong>%1$s</strong> Anda. <br/>Kelola situs aktif Anda dari %2$s akun Anda %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Lisensi Anda dinonaktifkan untuk URL ini. Aktifkan kembali dari <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Kelola Situs.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Terjemahan otomatis %1$s memerlukan lisensi aktif. Silakan %2$sperpanjang%3$s lisensi Anda atau beli yang baru %4$sdi sini%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Silakan %1$smasukkan%2$s kunci lisensi Anda untuk mengaktifkan terjemahan otomatis %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Sisa kata TranslatePress AI Anda kurang dari 5.000. Untuk terus menerjemahkan situs web Anda secara otomatis, silakan %sbeli kata AI tambahan dengan diskon dari akun Anda%s.',' Error: '=>' Kesalahan: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Situs web ini sudah diaktifkan dengan lisensi gratis. Setiap situs web hanya dapat menggunakan satu lisensi gratis. Silakan tingkatkan ke paket premium untuk mendapatkan lebih banyak kata TranslatePress AI dari %1$s akun Anda %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Anda tidak memiliki lisensi yang valid untuk <strong>TranslatePress</strong>. %1$sDapatkan secara gratis%2$s untuk mendapatkan akses ke TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>BARU:</strong> Add-on <strong>Different Domain per Language</strong> telah hadir! Tingkatkan SEO global Anda dan ciptakan pengalaman lokal dengan domain khusus negara seperti .de atau .fr. Tingkatkan ke <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business atau Developer</a> untuk mengaksesnya + lebih banyak keuntungan premium!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>BARU:</strong> Add-on <strong>Different Domain per Language</strong> telah hadir! Tingkatkan SEO global Anda dan ciptakan pengalaman lokal dengan domain khusus negara seperti .de atau .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Pelajari selengkapnya</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Kuota harian untuk karakter terjemahan mesin telah terlampaui. Silakan periksa halaman <strong>TranslatePress -> <a href="%s">Terjemahan Otomatis</a></strong> untuk informasi lebih lanjut.','Marketing optin'=>'Opt-in Pemasaran','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Setuju untuk menerima pemberitahuan pembaruan keamanan dan fitur, serta pelacakan diagnostik yang tidak sensitif.','TranslatePress Preferred User Language'=>'Bahasa Pilihan Pengguna TranslatePress','Preferred language to navigate the site'=>'Bahasa pilihan untuk menjelajahi situs','The language is automatically set based by the last visited language by the user.'=>'Bahasa diatur secara otomatis berdasarkan bahasa terakhir yang dikunjungi pengguna.','Always use this language'=>'Selalu gunakan bahasa ini','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Dengan mencentang pengaturan ini, bahasa pilihan akan tetap menjadi yang dipilih di atas dan tidak dapat diubah di frontend.<br>Bahasa ini akan digunakan dalam berbagai operasi seperti mengirim email kepada pengguna.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Halo! Sepertinya Anda telah menggunakan <strong>TranslatePress</strong> untuk menerjemahkan situs web Anda sudah beberapa waktu. Itu luar biasa! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Jika Anda dapat meluangkan waktu sejenak untuk menilainya di WordPress.org, akan sangat membantu kami (dan meningkatkan motivasi saya).','~ Razvan, developer of TranslatePress'=>'~ Razvan, pengembang TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Nilai TranslatePress di halaman plugin WordPress.org','Ok, I will gladly help!'=>'Oke, saya akan dengan senang hati membantu!','No, thanks.'=>'Tidak, terima kasih.','Full Language Names'=>'Nama Bahasa Lengkap','Short Language Names'=>'Nama Bahasa Singkat','Flags with Full Language Names'=>'Bendera dengan Nama Bahasa Lengkap','Flags with Short Language Names'=>'Bendera dengan Nama Bahasa Singkat','Only Flags'=>'Hanya Bendera','Full Language Names No HTML'=>'Nama Bahasa Lengkap Tanpa HTML','Bottom Right'=>'Kanan Bawah','Bottom Left'=>'Kiri Bawah','Top Right'=>'Kanan Atas','Top Left'=>'Kiri Atas','Dark'=>'Gelap','Light'=>'Terang','Deactivate'=>'Nonaktifkan','Activate'=>'Aktifkan','Invalid language code. Please try again.'=>'Kode bahasa tidak valid. Silakan coba lagi.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Kode bahasa hanya boleh berisi karakter A-Z a-z 0-9 - _. Periksa kode bahasa Anda di Pengaturan Umum TranslatePress.','Error! Duplicate URL slug values.'=>'Kesalahan! Nilai slug URL duplikat.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Anda tidak dapat memilih dua bahasa yang memiliki <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">kode ISO</a> yang sama tetapi formalitas berbeda karena hal tersebut akan menyebabkan <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">tag hreflang</a> duplikat.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Bahasa duplikat terdeteksi.<br>Setiap bahasa hanya dapat ditambahkan satu kali untuk memastikan manajemen terjemahan yang akurat.<br> Silakan ubah entri bahasa yang duplikat dan coba lagi. ','Current Language'=>'Bahasa Saat Ini','Opposite Language'=>'Bahasa Berlawanan','General'=>'Umum','Translate Site'=>'Terjemahkan Situs','Addons'=>'Pengaya','License'=>'Lisensi','Settings'=>'Pengaturan','Activate License'=>'Aktifkan Lisensi','Pro Features'=>'Fitur Pro','Need Help?'=>'Butuh Bantuan?','Recent community discussions'=>'Diskusi komunitas terbaru','Loading...'=>'Memuat...','Unable to load forum posts'=>'Tidak dapat memuat pos forum','Ask a Question'=>'Ajukan Pertanyaan','View All Topics'=>'Lihat Semua Topik','by'=>'oleh','Have a question?'=>'Punya pertanyaan?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Dapatkan bantuan langsung dari pengembang plugin, sarankan perbaikan, atau bagikan masukan Anda!','Tip for faster help:'=>'Tips untuk bantuan lebih cepat:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Sertakan apa yang Anda coba, apa yang Anda harapkan, dan apa yang terjadi. Tangkapan layar membantu!','Toggle support chat'=>'Alihkan obrolan dukungan','Ask the community'=>'Tanyakan ke komunitas','Close'=>'Tutup','Empty feed response'=>'Respons feed kosong','Unable to parse feed'=>'Tidak dapat mengurai feed','Just now'=>'Baru saja','%d hour ago'=>'%d jam yang lalu','%d day ago'=>'%d hari yang lalu','Source'=>'Sumber','Srcset'=>'Srcset','Alt attribute'=>'Atribut alt','Title attribute'=>'Atribut title','Anchor link'=>'Tautan jangkar','Placeholder attribute'=>'Atribut placeholder','Submit attribute'=>'Atribut submit','Text'=>'Teks','Video Poster'=>'Poster video','plural form'=>'bentuk jamak','one'=>'satu','few'=>'beberapa','many'=>'banyak','other'=>'lainnya','Saved'=>'Tersimpan','Save'=>'Simpan','Saving translation...'=>'Menyimpan terjemahan...','You have unsaved changes!'=>'Anda memiliki perubahan yang belum disimpan!','Discard changes'=>'Buang perubahan','Discard All'=>'Buang Semua','Loading Strings...'=>'Memuat String...','Select string to translate...'=>'Pilih string untuk diterjemahkan...','Close Editor'=>'Tutup Editor','From'=>'Dari','To'=>'Ke','Add Media'=>'Tambah Media','Other languages'=>'Bahasa lain','Context'=>'Konteks','View Website As'=>'Lihat Situs Sebagai','Available in our Pro Versions'=>'Tersedia di versi Pro kami','Select or Upload Media'=>'Pilih atau Unggah Media','Use this media'=>'Gunakan media ini','Translate'=>'Terjemahkan','Translate entire block element'=>'Terjemahkan seluruh elemen blok','Split block to translate strings individually'=>'Pisahkan blok untuk menerjemahkan string satu per satu','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Simpan perubahan terjemahan. Pintasan: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Pindah ke string berikutnya di daftar dropdown. Pintasan: CTRL(⌘) + ALT + Panah Kanan','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Pindah ke string sebelumnya di daftar dropdown. Pintasan: CTRL(⌘) + ALT + Panah Kiri','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Buang semua perubahan. Pintasan: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Buang perubahan pada kotak teks ini. Untuk membuang perubahan pada semua kotak teks gunakan pintasan: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Tutup tooltip','Quick Intro'=>'Pengenalan Singkat','Are you sure you want to split this phrase into smaller parts?'=>'Apakah Anda yakin ingin memecah frasa ini menjadi bagian-bagian yang lebih kecil?','This string is not ready for translation yet. <br>Try again in a moment...'=>'String ini belum siap untuk diterjemahkan. <br>Coba lagi sebentar...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Agar opsi ini berfungsi, harap perbarui add-on Browse as other role ke versi terbaru.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Untuk menerjemahkan slug, harap perbarui add-on SEO Pack ke versi terbaru.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Anda dapat menambahkan bahasa baru dari <a href="%s">Pengaturan->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Namun, Anda masih dapat menggunakan TranslatePress untuk <strong style="background: #f5fb9d;">memodifikasi string gettext</strong> yang tersedia di halaman Anda.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'String yang dibuat pengguna tidak dapat dimodifikasi, hanya yang dari tema dan plugin.','Extra Translation Features'=>'Fitur Terjemahan Ekstra','Support for 130+ Extra Languages'=>'Dukungan untuk 130+ Bahasa Ekstra','Access to TranslatePress AI'=>'Akses ke TranslatePress AI','Translate SEO Title, Description, Slug'=>'Terjemahkan Judul SEO, Deskripsi, Slug','Publish only when translation is complete'=>'Terbitkan hanya jika terjemahan sudah selesai','Translate by Browsing as User Role'=>'Terjemahkan dengan Menelusuri sebagai Peran Pengguna','Different Menu Items for each Language'=>'Item Menu Berbeda untuk Setiap Bahasa','Automatic User Language Detection'=>'Deteksi Otomatis Bahasa Pengguna','Upgrade to PRO'=>'Tingkatkan ke PRO','Upgrade to PRO with our biggest discount of the year!'=>'Tingkatkan ke PRO dengan diskon terbesar kami tahun ini!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Pada Black Friday ini, dapatkan akses ke fitur-fitur ini dan lainnya dengan harga yang jauh lebih murah:','No available suggestions'=>'Tidak ada saran yang tersedia','Suggestions from translation memory'=>'Saran dari memori terjemahan','Click to Copy'=>'Klik untuk Menyalin','Human Translation'=>'Terjemahan Manusia','Machine Translation'=>'Terjemahan Mesin','Text on this page is %s% translated into all languages.'=>'Teks di halaman ini telah diterjemahkan %s% ke semua bahasa.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% teks di halaman ini telah diterjemahkan ke %2$s.','This page is %1$s% translated into %2$s.'=>'Halaman ini telah diterjemahkan %1$s% ke %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Slug yang Anda coba edit terdapat di jenis slug lain: %s. Mengeditnya akan mengganti setiap kemunculan, terlepas dari jenis saat ini.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Arahkan kursor ke teks apa pun di halaman, klik %s,<br> lalu ubah terjemahan di bilah samping.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Jangan lupa Simpan Terjemahan. Gunakan pintasan keyboard CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Ubah bahasa untuk melihat perubahan terjemahan langsung di halaman.','Search for any text in this page in the dropdown.'=>'Cari teks apa pun di halaman ini di dropdown.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Lisensi %s Anda telah <span class="trp-license-status-emphasized">kadaluwarsa</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Harap perbarui lisensi Anda untuk terus mendapatkan akses ke TranslatePress AI, addon premium, pembaruan otomatis, dan dukungan.','Renew Now'=>'Perbarui Sekarang','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Black Friday kali ini, perbarui lisensi Anda dengan harga spesial</strong> untuk terus mendapatkan akses ke unduhan produk, pembaruan otomatis, dan dukungan.','Get Deal'=>'Dapatkan Penawaran','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Lisensi %s Anda telah <span class="trp-license-status-emphasized">dikembalikan dananya</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Harap beli lisensi baru untuk terus mendapatkan akses ke TranslatePress AI, addon premium, pembaruan otomatis, dan dukungan.','Purchase a new license'=>'Beli lisensi baru','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Lisensi %s Anda <span class="trp-license-status-emphasized">hilang atau tidak valid</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Silakan masukkan lisensi yang valid untuk mendapatkan akses ke TranslatePress AI, add-on premium, pembaruan otomatis, dan dukungan. Butuh kunci lisensi? %1$sBeli sekarang%2$s','Enter a valid license'=>'Masukkan lisensi yang valid','Slugs'=>'Slug','Meta Information'=>'Informasi Meta','String List'=>'Daftar String','Gettext Strings'=>'String Gettext','Images'=>'Gambar','Videos'=>'Video','Audios'=>'Audio','Dynamically Added Strings'=>'String yang Ditambahkan Secara Dinamis','Translation Editor'=>'Editor Terjemahan','Edit translations by visually selecting them on each site page'=>'Sunting terjemahan dengan memilihnya secara visual di setiap halaman situs','String Translation'=>'Terjemahan String','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Edit terjemahan slug URL, plugin, dan tema (email, formulir, dll.)','Current User'=>'Pengguna Saat Ini','Logged Out'=>'Tidak Masuk','Translate Page'=>'Terjemahkan Halaman','Add a New Language'=>'Tambah Bahasa Baru','Get a Free AI License'=>'Dapatkan Lisensi AI Gratis','Your License is Invalid'=>'Lisensi Anda Tidak Valid','Get More AI Words (%d left)'=>'Dapatkan Lebih Banyak Kata AI (%d tersisa)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Membuka pos di editor terjemahan. Pos harus disimpan sebagai draf atau diterbitkan terlebih dahulu.','Security check'=>'Pemeriksaan keamanan','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Peringatan:</strong> Beberapa string memiliki karakter yang mungkin dienkode secara tidak benar. Hal ini dapat mengakibatkan rusaknya query, sehingga halaman tidak diterjemahkan dalam mode live. Pertimbangkan untuk meninjau ulang string berikut atau metode outputnya.','TranslatePress data update'=>'Pembaruan data TranslatePress','We need to update your translations database to the latest version.'=>'Kami perlu memperbarui basis data terjemahan Anda ke versi terbaru.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Pembaruan akan memungkinkan pengeditan terjemahan teks yang dilokalkan dari plugin dan tema. Terjemahan yang ada akan tetap berfungsi seperti yang diharapkan.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'PENTING: Sangat disarankan untuk membuat cadangan basis data terlebih dahulu!\\nApakah Anda yakin ingin melanjutkan?','Run the updater'=>'Jalankan pembaruan','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Pembaruan akan memungkinkan pengeditan terjemahan slug. Terjemahan yang ada akan tetap berfungsi sebagaimana mestinya.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Silakan aktifkan Pengaya SEO dari <br/>WordPress -> Pengaturan -> TranslatePress -> bagian Pengaya','Go to Addons'=>'Buka Pengaya','The SEO Pack add-on allows translation of all the URL slugs:'=>'Pengaya SEO Pack memungkinkan penerjemahan semua slug URL:','Taxonomy slugs'=>'Slug taksonomi','Term slugs'=>'Slug istilah','Post slugs (this includes pages and custom post types)'=>'Slug pos (ini mencakup halaman dan jenis pos kustom)','Post type base slugs'=>'Slug dasar jenis pos','WooCommerce slugs'=>'Slug WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Add-on SEO Pack tersedia untuk SEMUA versi premium plugin.','Upgrade to Pro'=>'Tingkatkan ke Pro','Description'=>'Deskripsi','Article Section'=>'Bagian Artikel','Article Tag'=>'Tag Artikel','OG Title'=>'Judul OG','OG Site Name'=>'Nama Situs OG','OG Description'=>'Deskripsi OG','OG Image Alt'=>'Alt Gambar OG','Twitter Title'=>'Judul Twitter','Twitter Description'=>'Deskripsi Twitter','Twitter Image Alt'=>'Alt Gambar Twitter','Page Title'=>'Judul Halaman','Dublin Core Title'=>'Judul Dublin Core','Dublin Core Description'=>'Deskripsi Dublin Core','OG Image'=>'Gambar OG','OG Image Secure URL'=>'URL Aman Gambar OG','Twitter Image'=>'Gambar Twitter','Removing cdata dictionary strings for language %s...'=>'Menghapus string kamus cdata untuk bahasa %s...','Removing untranslated dictionary links for language %s...'=>'Menghapus tautan kamus yang belum diterjemahkan untuk bahasa %s...','Removing duplicated gettext strings for language %s...'=>'Menghapus string gettext yang diduplikasi untuk bahasa %s...','Removing duplicated dictionary strings for language %s...'=>'Menghapus string kamus yang diduplikasi untuk bahasa %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Menghapus string kamus yang belum diterjemahkan yang memiliki terjemahan tersedia untuk bahasa %s...','Inserting original strings for language %s...'=>'Memasukkan string asli untuk bahasa %s...','Cleaning original strings table for language %s...'=>'Membersihkan tabel string asli untuk bahasa %s...','Updating original string ids for language %s...'=>'Memperbarui ID string asli untuk bahasa %s...','Regenerating original meta table for language %s...'=>'Menghasilkan ulang tabel meta asli untuk bahasa %s...','Cleaning original meta table for language %s...'=>'Membersihkan tabel meta asli untuk bahasa %s...','Replacing original id NULL with value for language %s...'=>'Mengganti ID asli NULL dengan nilai untuk bahasa %s...','Inserting gettext original strings for language %s...'=>'Memasukkan string asli gettext untuk bahasa %s...','Cleaning gettext original strings table for language %s...'=>'Membersihkan tabel string asli gettext untuk bahasa %s...','Updating gettext original string ids for language %s...'=>'Memperbarui ID string asli gettext untuk bahasa %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Memigrasi slug taksonomi dan slug dasar jenis pos ke struktur tabel baru...','Migrating post slugs to new table structure for language %s...'=>'Memigrasi slug pos ke struktur tabel baru untuk bahasa %s...','Migrating term slugs to new table structure for language %s...'=>'Memigrasi slug istilah ke struktur tabel baru untuk bahasa %s...','Finishing up...'=>'Menyelesaikan...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Optimasi database tidak berhasil diselesaikan. Kami menyarankan untuk memulihkan database asli atau <a href="%s" >mencoba lagi.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Pembaruan dibatalkan! Akun pengguna Anda tidak memiliki kemampuan untuk melakukan pembaruan database.','Update aborted! Invalid nonce.'=>'Pembaruan dibatalkan! Nonce tidak valid.','Update aborted! Incorrect action.'=>'Pembaruan dibatalkan! Tindakan tidak benar.','Update aborted! Incorrect language code.'=>'Pembaruan dibatalkan! Kode bahasa salah.','Updating database to version %s+'=>'Memperbarui database ke versi %s+','Processing table for language %s...'=>'Memproses tabel untuk bahasa %s...','Back to TranslatePress Settings'=>'Kembali ke Pengaturan TranslatePress','Successfully updated database!'=>'Database berhasil diperbarui!',' done.'=>' selesai.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Semua plugin add-on TranslatePress individual <a href="%1$s" target="_blank">telah dihentikan</a> dan kini disertakan dalam versi premium Personal, Business, dan Developer TranslatePress. Silakan masuk ke <a href="%2$s" target="_blank">halaman akun</a> Anda, unduh versi premium baru, dan instal. Pengaturan add-on individual Anda akan dipindahkan.','Brand-new Language Switcher Settings are here!'=>'Pengaturan Pengalih Bahasa yang sepenuhnya baru telah hadir!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Jelajahi templat bawaan, ubah warna, gaya bendera, spasi, tata letak, dan lainnya. Gunakan pratinjau langsung untuk menyempurnakan pengalih bahasa Anda dalam hitungan detik.','Start customizing'=>'Mulai menyesuaikan','Read documentation'=>'Baca dokumentasi','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> memerlukan <strong><a href="http://php.net/manual/en/book.mbstring.php">Pustaka Multibyte String PHP</a></strong>. Silakan hubungi administrator server Anda untuk menginstalnya di server Anda.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Terdeteksi pembatasan kueri panjang pada hosting WPEngine. Beberapa halaman besar mungkin muncul tidak diterjemahkan. Anda dapat menghapus pembatasan dengan menambahkan berikut ini ke wp-config.php situs Anda: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Bendera Bahasa Kustom','The Language code of the added custom language cannot be empty.'=>'Kode bahasa dari bahasa kustom yang ditambahkan tidak boleh kosong.','The Language code of the added custom language is invalid.'=>'Kode bahasa dari bahasa kustom yang ditambahkan tidak valid.','The Automatic Translation Code of the added custom language is invalid.'=>'Kode Terjemahan Otomatis dari bahasa kustom yang ditambahkan tidak valid.','TranslatePress Add-ons'=>'Add-on TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Anda harus terlebih dahulu membeli versi ini untuk mengakses add-on %1$sdi sini%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Silakan %1$smasukkan kunci lisensi Anda%2$s terlebih dahulu untuk mengaktifkan addon ini.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Anda memerlukan lisensi aktif untuk mengakses addon. Perbarui atau beli yang baru %1$sdi sini%2$s.','Advanced Add-ons'=>'Add-on Lanjutan','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Addon ini memperluas plugin terjemahan Anda dan tersedia dalam paket Developer, Business, dan Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Legacy)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Dukungan SEO untuk slug halaman, judul halaman, deskripsi, serta informasi social graph Facebook dan Twitter. Atribut lang HTML diatur dengan benar.','Multiple Languages'=>'Beberapa Bahasa','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Tambahkan bahasa sebanyak yang Anda butuhkan untuk menjadikan proyek Anda global. Terbitkan bahasa Anda hanya ketika semua terjemahan selesai.','Pro Add-ons'=>'Addon Pro','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Addon ini memperluas plugin terjemahan Anda dan tersedia dalam paket Business dan Developer.','DeepL Automatic Translation'=>'Terjemahan Otomatis DeepL','Automatically translate your website through the DeepL API.'=>'Terjemahkan situs Anda secara otomatis melalui API DeepL.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Mendorong pengunjung untuk beralih ke bahasa pilihan mereka berdasarkan pengaturan browser atau alamat IP dan mengingat bahasa terakhir yang dikunjungi.','Translator Accounts'=>'Akun Penerjemah','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Buat akun penerjemah untuk pengguna baru atau izinkan pengguna yang sudah ada dan bukan administrator untuk menerjemahkan situs Anda.','Browse As User Role'=>'Telusuri Sebagai Peran Pengguna','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Telusuri situs Anda seperti yang dilakukan oleh peran pengguna tertentu. Sangat berguna untuk konten dinamis atau konten tersembunyi yang muncul untuk pengguna tertentu.','Navigation Based on Language'=>'Navigasi Berdasarkan Bahasa','Configure different menu items for different languages.'=>'Konfigurasikan item menu yang berbeda untuk bahasa yang berbeda.','Different Domain per Language'=>'Domain Berbeda per Bahasa','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Hubungkan domain atau subdomain terpisah ke masing-masing versi terjemahan Anda. Perkuat identitas lokal merek Anda dan tingkatkan performa SEO untuk setiap bahasa yang Anda dukung.','Recommended Plugins'=>'Plugin yang Direkomendasikan','A short list of plugins you can use to extend your website.'=>'Daftar singkat plugin yang dapat Anda gunakan untuk memperluas situs web Anda.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Kumpulkan lebih banyak informasi pengguna di formulir pendaftaran dengan bantuan bidang profil pengguna kustom dari Profile Builder dan/atau tambahkan proses Konfirmasi Email untuk memverifikasi akun pelanggan Anda.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Terima pembayaran pengguna, buat paket langganan, dan batasi konten di situs keanggotaan Anda.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Buat otomasi dan alur kerja tanpa kode di situs WordPress Anda. Hubungkan plugin, situs, dan aplikasi Anda dengan mudah.','Save Changes'=>'Simpan Perubahan','TranslatePress Errors'=>'Kesalahan TranslatePress','There are no logged errors.'=>'Tidak ada kesalahan yang tercatat.','Change language'=>'Ubah bahasa','Website language selector'=>'Pemilih bahasa situs web','WordPress Translation Plugin'=>'Plugin Terjemahan WordPress','Available languages'=>'Bahasa yang tersedia','Language Switcher update notice'=>'Pemberitahuan pembaruan pengalih bahasa','Legacy language switcher is currently enabled'=>'Pengalih bahasa lawas saat ini diaktifkan','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Kami telah meningkatkan pengalih bahasa untuk kustomisasi yang lebih kaya dan pengalaman pengguna yang lebih baik.<br>Untuk menggunakan konfigurator baru, nonaktifkan <strong>Muat pengalih bahasa lawas</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Catatan: Anda dapat beralih kembali kapan saja dari <strong>Pengaturan Lanjutan → <a href="%s">Pemecahan Masalah</a></strong>.','Enable the new switcher'=>'Aktifkan pengalih baru','Your License Key is valid.'=>'Kunci lisensi Anda valid.','Your License Key is invalid.'=>'Kunci lisensi Anda tidak valid.','Your License has expired.'=>'Lisensi Anda telah kedaluwarsa.','Deactivate License'=>'Nonaktifkan Lisensi','Add a license key'=>'Tambahkan kunci lisensi','License Key'=>'Kunci Lisensi','Manage your license in your %1$s.'=>'Kelola lisensi Anda di %1$s Anda.','Account Page'=>'Halaman Akun','Don’t have a TranslatePress AI License Key?'=>'Belum memiliki Kunci Lisensi TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Anda bisa mendapatkannya %1$sgratis%2$s dengan membuat akun gratis. Termasuk:','Access to TranslatePress AI for instant automatic translations'=>'Akses ke TranslatePress AI untuk terjemahan otomatis instan','2000 AI words to translate automatically'=>'2000 kata AI untuk diterjemahkan secara otomatis','Get a free License Today'=>'Dapatkan Lisensi Gratis Hari Ini','Debug Information'=>'Informasi Debug','Debug Data for License Checking'=>'Data Debug untuk Pemeriksaan Lisensi','Debug Data for License Activation'=>'Data Debug untuk Aktivasi Lisensi','Get more AI words and unlock all features with TranslatePress Pro.'=>'Dapatkan lebih banyak kata AI dan buka kunci semua fitur dengan TranslatePress Pro.','Upgrade now ↗'=>'Tingkatkan sekarang ↗','Already purchased a Premium version?'=>'Sudah membeli versi Premium?','Go to your %1$s'=>'Buka %1$s Anda','TranslatePress.com Account'=>'Akun TranslatePress.com','Download & Install the Pro plugin'=>'Unduh & Instal plugin Pro','Learn More'=>'Pelajari Selengkapnya','Get a translation volume estimate with a detailed breakdown per page'=>'Dapatkan estimasi volume terjemahan dengan rincian detail per halaman','Find how many translatable words are on your website'=>'Cari tahu berapa banyak kata yang dapat diterjemahkan di situs web Anda','Enable Automatic Translation'=>'Aktifkan Terjemahan Otomatis','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Untuk menggunakan <strong>DeepL</strong> untuk terjemahan otomatis, aktifkan add-on Pro ini dari <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Terjemahan otomatis <strong>DeepL</strong> tersedia sebagai <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Dengan upgrade, Anda akan mendapatkan akses ke semua add-on berbayar, dukungan premium, dan membantu mendanai pengembangan TranslatePress di masa depan.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Harap dicatat bahwa penggunaan API DeepL dikenakan biaya secara terpisah. Lihat <a href="https://www.deepl.com/pro.html#developer">informasi harga DeepL</a>.','TranslatePress Pro Add-ons'=>'Add-on TranslatePress Pro','Test API credentials'=>'Uji Kredensial API','Check if the selected translation engine is configured correctly.'=>'Periksa apakah mesin penerjemahan yang dipilih dikonfigurasi dengan benar.','Alternative Engines'=>'Mesin Alternatif','Switch to TranslatePress AI'=>'Beralih ke TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Integrasikan terjemahan mesin langsung dengan situs web WordPress Anda.','More info'=>'Info selengkapnya','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Pilih mesin yang ingin Anda gunakan agar %1$s secara otomatis menerjemahkan situs web Anda.','Automatic Translation Settings'=>'Pengaturan Terjemahan Otomatis','AI Words Low Notification'=>'Notifikasi Kata AI Rendah','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Terima notifikasi email ketika jumlah kata TranslatePress AI Anda turun di bawah ambang batas yang ditentukan.','This feature is only available when using the TranslatePress AI translation engine.'=>'Fitur ini hanya tersedia saat menggunakan mesin terjemahan TranslatePress AI.','Notification Email'=>'Email Notifikasi','The email address where the low AI words notification will be sent.'=>'Alamat email tempat notifikasi kata AI rendah akan dikirim.','Word Threshold'=>'Ambang Batas Kata','words'=>'kata','You will be notified when remaining AI words drop below this number.'=>'Anda akan diberi tahu ketika sisa kata AI turun di bawah angka ini.','Automatically Translate Slugs'=>'Penerjemahan Slug Otomatis','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Hasilkan terjemahan otomatis slug untuk pos, halaman, dan Custom Post Type.<br/>Slug akan diterjemahkan secara otomatis mulai dari penyegaran kedua setiap halaman.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Fitur ini hanya tersedia di versi berbayar. Tingkatkan TranslatePress dan buka kunci lebih banyak fitur premium.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Memerlukan <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> untuk diinstal dan diaktifkan.','Upgrade now'=>'Tingkatkan sekarang','Block Crawlers'=>'Blokir Crawler','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Mencegah crawler memicu terjemahan otomatis di situs web Anda.<br>Ini tidak akan mencegah crawler mengakses halaman situs ini.','Limit machine translation / characters per day'=>'Batasi terjemahan mesin / karakter per hari','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Tambahkan batas pada jumlah karakter yang diterjemahkan secara otomatis agar Anda dapat mengatur anggaran proyek Anda dengan lebih baik.','characters per day'=>'karakter per hari','Today\'s Character Count: '=>'Jumlah Karakter Hari Ini: ','Log machine translation queries.'=>'Catat kueri terjemahan mesin.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Hanya aktifkan untuk tujuan pengujian. Dapat memengaruhi performa.<br>Semua catatan disimpan di tabel basis data wp_trp_machine_translation_log. Gunakan plugin seperti <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> untuk menelusuri log atau langsung dari pengelola basis data Anda (PHPMyAdmin, dll.)','Test API Credentials'=>'Uji Kredensial API','HTTP Referrer: '=>'HTTP Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Gunakan HTTP Referrer ini jika API memungkinkan Anda membatasi penggunaan kunci dari Dasbornya.','Response'=>'Respons','Response Body'=>'Isi Respons','Entire Response From wp_remote_get():'=>'Respons lengkap dari wp_remote_get():','All Languages'=>'Semua Bahasa','Select the languages you wish to make your website available in.'=>'Pilih bahasa yang ingin Anda sediakan untuk situs web Anda.','Formality'=>'Formalitas','Code'=>'Kode','Slug'=>'Slug','Default'=>'Bawaan','Formal'=>'Formal','Informal'=>'Informal','Language'=>'Bahasa','This language does not support formality. '=>'Bahasa ini tidak mendukung formalitas. ','Are you sure you want to remove this language?'=>'Apakah Anda yakin ingin menghapus bahasa ini?','Custom Languages'=>'Bahasa Kustom','To Add more languages activate the Multiple Languages Addon'=>'Untuk menambah bahasa, aktifkan Add-on Multiple Languages','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Anda memerlukan lisensi aktif untuk menambah bahasa. Verifikasi di %1$sakun%2$s Anda bahwa lisensi Anda valid.','Please %1$senter your license%2$s key first to add more languages.'=>'Silakan %1$smasukkan kunci lisensi Anda%2$s terlebih dahulu untuk menambah bahasa.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Menambah lebih dari dua bahasa merupakan fitur berbayar. Tingkatkan TranslatePress dan buka lebih banyak fitur premium.','Website Languages'=>'Bahasa Situs Web','Default Language'=>'Bahasa Bawaan','Select the language your content is written in.'=>'Pilih bahasa yang digunakan untuk konten Anda.','WARNING. Changing the default language will invalidate existing translations.'=>'PERINGATAN. Mengubah bahasa bawaan akan membuat terjemahan yang ada tidak valid.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Bahkan mengubah dari en_US ke en_GB, karena keduanya dianggap sebagai dua bahasa berbeda.','In most cases changing the default flag is all it is needed: '=>'Dalam kebanyakan kasus, mengubah bendera bawaan sudah cukup: ','replace the default flag'=>'ganti bendera bawaan','Re-run Setup Wizard'=>'Jalankan Ulang Panduan Penyiapan','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Panduan penyiapan memungkinkan Anda menyiapkan TranslatePress dengan cepat. Anda dapat memulainya kapan saja.','Language Settings'=>'Pengaturan Bahasa','Use Native language name'=>'Gunakan nama bahasa asli','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Centang jika Anda ingin menampilkan bahasa dalam nama aslinya. Jika tidak, bahasa akan ditampilkan dalam bahasa Inggris.','Use a subdirectory for the default language'=>'Gunakan subdirektori untuk bahasa bawaan','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Centang jika Anda ingin menambahkan subdirektori dalam URL untuk bahasa bawaan.</br>Dengan mencentang opsi ini, bahasa bawaan yang dilihat pengunjung situs web akan menjadi yang pertama dalam daftar "Semua Bahasa".','Force language in custom links'=>'Paksakan bahasa dalam tautan kustom','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Pilih Ya jika Anda ingin memaksa tautan kustom tanpa pengkodean bahasa untuk mempertahankan bahasa yang sedang dipilih.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Gunakan shortcode di halaman atau widget apa pun.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Anda juga dapat menambahkan <a href="%s" title="Language Switcher Block Documentation">Blok Pengalih Bahasa</a> di Editor WP Gutenberg.','Menu item'=>'Item menu','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Pergi ke  %1$s Tampilan -> Menu%2$s untuk menambahkan bahasa ke Pengalih Bahasa di menu apa pun.','Learn more in our documentation.'=>'Pelajari lebih lanjut di dokumentasi kami.','Floating language selection'=>'Pemilihan bahasa mengambang','Add a floating dropdown that follows the user on every page.'=>'Tambahkan dropdown mengambang yang mengikuti pengguna di setiap halaman.','Show "Powered by TranslatePress"'=>'Tampilkan "Powered by TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Tampilkan label kecil "Powered by TranslatePress" di pengalih bahasa mengambang.','5 Days to Better Multilingual Websites'=>'5 Hari Menuju Situs Web Multibahasa yang Lebih Baik','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sIkuti kursus onboarding GRATIS & EKSKLUSIF kami%s dan pelajari cara meningkatkan trafik multibahasa Anda, menjangkau pasar internasional, serta menghemat waktu & uang sambil memaksimalkan TranslatePress!','Invalid email address'=>'Alamat email tidak valid','Your email'=>'Email Anda','Sign me up!'=>'Daftarkan saya!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Daftar dengan alamat email Anda dan terima panduan email 5-bagian untuk membantu Anda memaksimalkan potensi TranslatePress.','Dismiss email course notification'=>'Tutup notifikasi kursus email','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hai %s,<br>Jangan lewatkan pembaruan penting - aktifkan notifikasi pembaruan keamanan dan fitur, serta pelacakan diagnostik yang tidak sensitif.','Allow & Continue'=>'Izinkan & Lanjutkan','Skip'=>'Lewati','This will allow TranslatePress to:'=>'Ini akan memungkinkan TranslatePress untuk:','Your profile overview'=>'Ringkasan profil Anda','Name and email address'=>'Nama dan alamat email','Admin Notices'=>'Pemberitahuan Admin','Updates, announcements, marketing, no spam'=>'Pembaruan, pengumuman, pemasaran, tidak ada spam','Plugin status & settings'=>'Status & pengaturan plugin','Active, Deactivated, installed version and settings'=>'Aktif, nonaktif, versi terinstal, dan pengaturan','Privacy Policy'=>'Kebijakan Privasi','Terms of Service'=>'Ketentuan Layanan','Support'=>'Dukungan','Documentation'=>'Dokumentasi','Add Extra AI Words'=>'Tambah Kata AI Ekstra','Optimize TranslatePress database tables'=>'Optimalkan tabel basis data TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>CATATAN PENTING:</strong> Sebelum melakukan tindakan ini, sangat disarankan untuk membuat cadangan basis data terlebih dahulu.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'PENTING: Sangat disarankan untuk membuat cadangan basis data terlebih dahulu!! Apakah Anda yakin ingin melanjutkan?','Operations to perform'=>'Operasi yang akan dilakukan','Remove CDATA for original and dictionary strings'=>'Hapus CDATA untuk string asli dan string kamus','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Menghapus CDATA dari tabel trp_original_strings dan trp_dictionary_*.<br>Jenis konten ini seharusnya tidak terdeteksi oleh TranslatePress. Konten ini mungkin telah dimasukkan ke dalam basis data pada versi plugin yang lebih lama.','Remove untranslated links from dictionary tables'=>'Hapus tautan yang belum diterjemahkan dari tabel kamus','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Menghapus tautan dan gambar yang belum diterjemahkan dari semua tabel trp_dictionary_*. Tabel-tabel ini berisi terjemahan untuk string yang diinput pengguna seperti konten pos, judul pos, menu, dll.','Remove duplicate rows for gettext strings'=>'Hapus baris duplikat untuk string gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Membersihkan semua tabel trp_gettext_* dari baris duplikat. Tabel-tabel ini berisi terjemahan untuk string tema dan plugin.','Remove duplicate rows for dictionary strings'=>'Hapus baris duplikat untuk string kamus','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Membersihkan semua tabel trp_dictionary_* dari baris duplikat. Tabel-tabel ini berisi terjemahan untuk string yang diinput pengguna seperti konten pos, judul pos, menu, dll.','Remove duplicate rows for original dictionary strings'=>'Hapus baris duplikat untuk string kamus asli','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Membersihkan tabel trp_original_strings dari baris duplikat. Tabel ini berisi string dalam bahasa default, tanpa terjemahan apa pun.<br>Tabel trp_original_meta, yang berisi informasi meta yang mengacu pada ID induk pos, juga diregenerasi.<br>Duplikat seperti itu dapat muncul dalam situasi pengecualian akibat perilaku tak terduga.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Ganti string gettext yang memiliki ID asli NULL dengan ID asli yang benar','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Memperbaiki masalah kasus tepi di mana beberapa string gettext memiliki ID asli yang diatur secara tidak benar ke NULL, menyebabkan masalah di Translation Editor.<br>Operasi ini memperbaiki ID asli di tabel trp_gettext_*.<br>Hanya centang opsi ini jika Anda mengalami masalah di Translation Editor saat mengklik pensil hijau tidak menampilkan string gettext untuk diterjemahkan di bilah sisi kiri.<br>Jika tidak, silakan biarkan opsi ini tidak dicentang karena ini adalah operasi yang intensif.','Optimize Database'=>'Optimalkan Basis Data','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Memperbarui tabel TranslatePress. Mohon biarkan jendela ini tetap terbuka.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Bahasa yang tidak aktif akan tetap terlihat dan aktif untuk admin. Bagi pengguna lain, bahasa tersebut tidak akan terlihat di pengalih bahasa dan juga tidak dapat diakses.','unknown'=>'tidak diketahui','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Pengaya Extra Languages</strong> memerlukan TranslatePress versi %1$s atau lebih tinggi. Anda saat ini menggunakan versi %2$s. Mohon perbarui TranslatePress untuk mengaktifkan fitur ini.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Perubahan terjemahan slug otomatis dan manual yang dilakukan saat <strong>TranslatePress - Multilingual</strong> 2.8.4 aktif harus dihapus karena beberapa masalah pada versi tersebut. Semua terjemahan slug dari sebelum versi itu sekarang digunakan. Terima kasih atas pengertian Anda!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Jika Anda benar-benar membutuhkannya, terjemahan yang dihapus dapat ditemukan di tabel trp_slug_original_obsolete dan trp_slug_translation_obsolete.','View Docs'=>'Lihat Dokumentasi','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Tetapkan domain atau subdomain yang berbeda untuk setiap bahasa. Ketika pengunjung mengakses domain ini, TranslatePress memuat terjemahan bahasa yang sesuai secara langsung tanpa pengalihan.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Contoh: %1$s untuk bahasa Inggris, %2$s untuk bahasa Spanyol, %3$s untuk bahasa Prancis.','Before enabling:'=>'Sebelum mengaktifkan:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Pastikan domain Anda terdaftar, diarahkan ke server Anda, dan memiliki sertifikat SSL yang dikonfigurasi.','Domain'=>'Domain','Map this language to a different domain or sub-domain.'=>'Petakan bahasa ini ke domain atau sub-domain yang berbeda.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Isi otomatis dengan domain saat ini','Check DNS'=>'Periksa DNS','Checking DNS...'=>'Memeriksa DNS...','DNS is correctly configured!'=>'DNS sudah dikonfigurasi dengan benar!','DNS check failed. Please verify your domain configuration.'=>'Pemeriksaan DNS gagal. Silakan verifikasi konfigurasi domain Anda.','This domain is already assigned to another language.'=>'Domain ini sudah ditetapkan ke bahasa lain.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Different Domain per Language add-on</strong> memerlukan TranslatePress versi %1$s atau lebih tinggi. Saat ini Anda menggunakan versi %2$s. Silakan perbarui TranslatePress untuk mengaktifkan fitur ini.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Catatan: Opsi ini dinonaktifkan saat Different Domain for Language addon aktif.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Domain diperlukan saat pemetaan domain diaktifkan. Tombol alih telah dinonaktifkan untuk bahasa dengan domain kosong.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: Domain yang sama tidak dapat ditetapkan ke beberapa bahasa. Tombol alih telah dinonaktifkan untuk domain duplikat.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: Domain bahasa tidak boleh sama dengan URL situs utama. Tombol alih telah dinonaktifkan untuk domain yang cocok.','Please enter a domain.'=>'Silakan masukkan domain.','Invalid domain format.'=>'Format domain tidak valid.','Could not reach domain: %s'=>'Gagal mengakses domain: %s','Domain returned HTTP status %d.'=>'Domain mengembalikan status HTTP %d.','Domain is reachable!'=>'Domain dapat dijangkau!','Limit this menu item to the following languages'=>'Batasi item menu ini ke bahasa berikut','Date format'=>'Format tanggal','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Sesuaikan format tanggal untuk setiap bahasa yang diterjemahkan.<br/>Biarkan kosong untuk pengaturan default WP atau lihat informasi selengkapnya <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">di sini</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Untuk mengedit bahasa TranslatePress yang sudah ada, masukkan kode bahasa dan isi hanya kolom yang ingin Anda timpa (mis. Nama bahasa, Bendera).<br>Anda juga dapat menambahkan bahasa kustom baru. Bahasa-bahasa tersebut akan tersedia di bawah Pengaturan Umum, daftar Semua Bahasa, di mana slug URL dapat diedit.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Untuk bendera kustom, unggah gambar terlebih dahulu ke pustaka media lalu tempel URL-nya.<br>Mengubah atau menghapus bahasa kustom akan memengaruhi terjemahan dan URL situs.<br>Kode bahasa dan kode ISO hanya boleh mengandung karakter alfabet, karakter numerik, "-" dan "_".<br>Kode ISO dapat ditemukan di <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Kode ISO Google</a> dan <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">Kode Target DeepL</a>.','Language code'=>'Kode bahasa','Language name'=>'Nama bahasa','Native name'=>'Nama asli','ISO Code'=>'Kode ISO','Flag URL'=>'URL bendera','Text RTL'=>'Teks RTL','Custom language'=>'Bahasa kustom','Disable dynamic translation'=>'Nonaktifkan terjemahan dinamis','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Menonaktifkan deteksi string yang ditampilkan secara dinamis menggunakan JavaScript. <br/>String yang dimuat melalui panggilan AJAX sisi server akan tetap diterjemahkan.','Disable translation for gettext strings'=>'Nonaktifkan terjemahan untuk string gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'String Gettext adalah string yang dihasilkan oleh tema dan plugin. <br> Menerjemahkan jenis string ini melalui TranslatePress mungkin tidak diperlukan jika sudah diterjemahkan menggunakan sistem file terjemahan .po/.mo.<br>Mengaktifkan opsi ini dapat meningkatkan performa pemuatan halaman situs Anda dalam kasus tertentu. Kekurangannya adalah Anda tidak lagi dapat mengedit terjemahan gettext menggunakan TranslatePress, maupun memanfaatkan penerjemahan otomatis pada string ini.','Gettext Strings translation is disabled'=>'Terjemahan string Gettext dinonaktifkan','To enable it go to '=>'Untuk mengaktifkannya, buka ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Pengaturan Lanjutan->Debug->Nonaktifkan terjemahan untuk string Gettext',' and uncheck the Checkbox.'=>' dan hapus centang pada kotak centang.','Dismiss'=>'Tutup','Exclude translated links from sitemap'=>'Kecualikan tautan terjemahan dari sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Jangan sertakan tautan terjemahan dalam sitemaps yang dihasilkan oleh plugin SEO.<br/>Memerlukan <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> Add-on SEO Pack</a> untuk diinstal dan diaktifkan.','Disable post container tags for post title'=>'Nonaktifkan tag kontainer pos untuk judul pos','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Ini menonaktifkan pengindeksan pencarian judul pos dalam bahasa terjemahan.<br/>Berguna ketika judul pos tidak mengizinkan HTML sehingga merusak halaman.','Disable post container tags for post content'=>'Nonaktifkan tag kontainer pos untuk konten pos','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Ini menonaktifkan pengindeksan pencarian konten pos dalam bahasa terjemahan.<br/>Berguna ketika konten pos tidak mengizinkan HTML sehingga merusak halaman.','Do not translate certain paths'=>'Jangan terjemahkan jalur tertentu','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Pilih jalur mana yang dapat diterjemahkan. Mendukung wildcard di akhir jalur.<br>Misalnya, untuk mengecualikan https://example.com/some/path Anda dapat menggunakan aturan /some/path/ atau /some/*.<br>Masukkan setiap aturan pada barisnya sendiri. Untuk mengecualikan halaman beranda gunakan {home}.','Exclude Paths From Translation'=>'Kecualikan Jalur Dari Penerjemahan','Translate Only Certain Paths'=>'Terjemahkan Hanya Jalur Tertentu','Enable the hreflang x-default tag for language:'=>'Aktifkan tag hreflang x-default untuk bahasa:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Mengaktifkan hreflang="x-default" untuk sebuah bahasa secara keseluruhan. Lihat dokumentasi untuk detail lebih lanjut.','Translate numbers and numerals'=>'Terjemahkan angka dan numeral','Enable translation of numbers ( e.g. phone numbers)'=>'Aktifkan penerjemahan angka (mis. nomor telepon)','Selector'=>'Selektor','Exclude from dynamic translation'=>'Kecualikan dari penerjemahan dinamis','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Tidak menerjemahkan string secara dinamis yang ditemukan dalam node html yang cocok dengan selektor ini.<br>Mengecualikan semua turunan node HTML yang cocok dengan selektor ini dari penerjemahan menggunakan JavaScript.<br/>String ini akan tetap diterjemahkan di sisi server jika memungkinkan.','Gettext String'=>'String Gettext','Exclude Gettext Strings'=>'Kecualikan String Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Kecualikan string ini agar tidak diterjemahkan sebagai string Gettext oleh TranslatePress. Biarkan domain kosong untuk memperhitungkan semua string Gettext apa pun.<br/>Masih dapat diterjemahkan melalui file po/mo.','Exclude selectors only from automatic translation'=>'Kecualikan selektor hanya dari terjemahan otomatis','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Tidak menerjemahkan string secara otomatis yang ditemukan dalam node html yang cocok dengan selektor ini.<br>Mengecualikan semua turunan node HTML yang cocok dengan selektor ini dari penerjemahan otomatis.<br>Penerjemahan manual string ini masih dimungkinkan.','Exclude selectors from translation'=>'Kecualikan selektor dari terjemahan','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Tidak menerjemahkan string yang ditemukan dalam node html yang cocok dengan selektor ini.<br>Mengecualikan semua turunan node HTML yang cocok dengan selektor ini dari penerjemahan.<br>String ini tidak dapat diterjemahkan secara manual maupun otomatis.','String'=>'String','Exclude strings from automatic translation'=>'Kecualikan string dari penerjemahan otomatis','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Tidak menerjemahkan string ini secara otomatis (mis. nama, kata teknis...)<br>Paragraf yang memuat string ini akan tetap diterjemahkan kecuali bagian yang ditentukan.','Fix broken HTML'=>'Perbaiki HTML yang rusak','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Upaya umum untuk memperbaiki HTML yang rusak atau hilang pada halaman terjemahan.<br/>','Force slash at end of home url:'=>'Paksa garis miring di akhir home url:','Ads a slash at the end of the home_url() function'=>'Menambahkan garis miring di akhir fungsi home_url()','Show Both (recommended)'=>'Tampilkan Keduanya (disarankan)','Remove Country Locale'=>'Hapus Locale Negara','Remove Region Independent Locale'=>'Hapus Locale Independen Wilayah','Remove duplicate hreflang'=>'Hapus hreflang duplikat','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Pilih tag hreflang mana yang akan muncul di situs web Anda.<br/>Kami menyarankan untuk menampilkan kedua jenis tag hreflang sebagaimana diindikasikan oleh <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">dokumentasi Google</a>.<br/>Menghapus Locale Negara ketika memiliki beberapa Locale Negara dari bahasa yang sama (mis. English UK dan English US) akan mengakibatkan ditampilkannya hanya satu tag hreflang dengan tautan ke salah satu locale wilayah untuk bahasa tersebut.','Default (example: en-US, fr-CA, etc.)'=>'Default (contoh: en-US, fr-CA, dll.)','Regional (example: en, fr, es, etc.)'=>'Regional (contoh: en, fr, es, dll.)','HTML Lang Attribute Format'=>'Format Atribut Lang HTML','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Ubah atribut lang pada tag html ke format yang menyertakan regional negara atau tidak. <br>Dalam HTML, atribut lang (<html lang="en-US">)  harus digunakan untuk  menentukan bahasa konten teks agar  browser dapat menampilkan atau memproses  konten Anda dengan benar (mis. untuk  pemenggalan kata, penataan gaya, pemeriksaan ejaan, dll).','Load legacy Language Switcher'=>'Muat pengalih bahasa lawas','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Berlaku untuk semua jenis pengalih bahasa (melayang, shortcode, dan menu). Jika diaktifkan, situs akan kembali menggunakan pengalih bahasa asli yang dikonfigurasi di tab Pengaturan Umum, menggantikan versi baru yang dapat disesuaikan. Pengaturan pengalih bahasa yang ada akan tetap tersimpan, tetapi akan diabaikan selama opsi ini aktif.','Load legacy SEO Pack Add-On'=>'Muat add-on SEO Pack lawas','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Jika migrasi terbaru ke penulisan ulang slug baru menimbulkan masalah, atur ini ke Ya untuk menggunakan metode lama <br> Silakan <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">buka tiket dukungan</a> untuk memberi tahu kami masalah yang Anda alami.','Manual Translation Only'=>'Hanya terjemahan manual','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress secara proaktif memindai dan menyimpan string dalam basis data ketika pengguna mengakses halaman terjemahan. <br>Pengaturan ini menonaktifkan fungsionalitas ini dan hanya mengizinkan penerjemahan dan penyimpanan string saat berada di dalam Editor Terjemahan. <br>Juga menonaktifkan penerjemahan mesin di luar Editor Terjemahan, memberi Anda kontrol yang lebih baik atas pengeluaran karakter, dengan hanya menerjemahkan halaman yang Anda kunjungi di Editor Terjemahan.','Open language switcher only on click'=>'Buka pengalih bahasa hanya dengan klik','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Buka shortcode pengalih bahasa dengan mengkliknya, bukan dengan mengarahkan kursor.<br> Tutup dengan mengkliknya, mengklik di mana saja pada layar, atau dengan menekan tombol escape. Ini hanya akan memengaruhi shortcode pengalih bahasa.','Show opposite language in the language switcher'=>'Tampilkan bahasa berlawanan di pengalih bahasa','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Mengubah pengalih bahasa menjadi tombol yang menampilkan bahasa lain yang tersedia, bukan bahasa saat ini.<br> Hanya berfungsi ketika terdapat tepat dua bahasa, bahasa default dan bahasa terjemahan.<br>Ini akan memengaruhi shortcode pengalih bahasa dan pengalih bahasa melayang juga.<br> Untuk mencapai ini pada pengalih bahasa menu, buka Tampilan->Menu->Pengalih Bahasa dan pilih Bahasa Berlawanan.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Klik di sini</a> untuk mengakses alat optimasi basis data.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Ini membantu menghapus kemungkinan duplikat terjemahan, membersihkan data yang tidak perlu, dan memperbaiki kemungkinan masalah metadata.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Di sini</a> Anda dapat melihat 5 error SQL terakhir yang relevan dengan TranslatePress jika ada.','Troubleshooting'=>'Penyelesaian Masalah','Exclude Gettext strings'=>'Kecualikan string Gettext','Debug'=>'Debug','Custom languages'=>'Bahasa kustom','Miscellaneous options'=>'Opsi lainnya','Exclude strings & pages'=>'Kecualikan string & halaman','Automatic Translation Memory'=>'Memori Terjemahan Otomatis','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Gunakan terjemahan yang sama untuk teks yang mirip. String harus memiliki tingkat kemiripan 95%.<br>Membantu mencegah kehilangan terjemahan yang ada saat memperbaiki kesalahan ketik atau melakukan penyesuaian kecil pada teks asli. <br>Jika terjemahan sudah ada untuk string asli yang sangat mirip, maka akan otomatis digunakan untuk string asli saat ini.<br>Tidak berfungsi saat mengubah teks yang merupakan bagian dari blok terjemahan kecuali teks baru digabungkan kembali secara manual dalam blok terjemahan.<br>Setiap string harus memiliki minimal 50 karakter.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'PERINGATAN: Fitur ini dapat berdampak negatif pada waktu muat halaman dalam bahasa sekunder, terutama dengan database besar (misalnya situs web dengan banyak halaman atau produk). Jika Anda mengalami waktu muat yang lambat, nonaktifkan ini dan coba lagi.','Fix missing dynamic content'=>'Perbaiki konten dinamis yang hilang','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Dapat membantu memperbaiki konten yang hilang yang disisipkan menggunakan JavaScript. <br> Menampilkan konten yang disisipkan secara dinamis dalam bahasa asli sesaat sebelum permintaan terjemahan selesai.','Filter Gettext wrapping from post content and title'=>'Saring pembungkus Gettext dari konten dan judul pos','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Menyaring pembungkus gettext seperti #!trpst#trp-gettext dari semua konten pos dan judul pos yang diperbarui. Tidak memengaruhi konten pos sebelumnya. <br/><strong>Backup database disarankan sebelum mengaktifkannya.</strong>','Filter Gettext wrapping from post meta'=>'Saring pembungkus Gettext dari meta pos','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Menyaring pembungkus gettext seperti #!trpst#trp-gettext dari semua meta pos yang diperbarui. Tidak memengaruhi meta pos sebelumnya. <br/><strong>Backup database disarankan sebelum mengaktifkannya.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Kunci API Google Translate','Add your API Key here...'=>'Tambahkan Kunci API Anda di sini...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Kunjungi <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">tautan ini</a> untuk melihat cara menyiapkan kunci API, <strong>mengontrol biaya API</strong>, dan menetapkan pembatasan referrer HTTP.','Your HTTP referrer is: %s'=>'Referrer HTTP Anda adalah: %s','There was an error on the server processing your Google Translate key.'=>'Terjadi kesalahan di server saat memproses kunci Google Translate Anda.','There was an error with your Google Translate key.'=>'Terjadi kesalahan pada kunci Google Translate Anda.','Please check your TranslatePress license key.'=>'Silakan periksa kunci lisensi TranslatePress Anda.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Tidak ada lisensi aktif yang terdeteksi untuk situs web ini.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Untuk mengaktifkan Terjemahan Otomatis menggunakan TranslatePress AI, Anda memerlukan kunci lisensi dengan membuat akun gratis.','Create your Free Account'=>'Buat akun gratis Anda',' or '=>' atau ','Enter your license key'=>'Masukkan kunci lisensi Anda',' Or %1$spurchase one here%2$s'=>' Atau %1$sbeli di sini%2$s','Your free account includes: '=>'Akun gratis Anda mencakup: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Dapatkan lebih banyak kata AI dan aktifkan semua fitur AI dengan TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Anda memiliki <strong>lisensi</strong> %s yang valid.',' words remaining. '=>' kata tersisa. ','Recheck'=>'Periksa ulang','Rechecking...'=>'Memeriksa ulang...','Done.'=>'Selesai.','Manage your license & quota on the %s'=>'Kelola lisensi & kuota Anda di %s','TranslatePress.com Account Page'=>'Halaman Akun TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Dukungan SEO untuk slug halaman, judul halaman, deskripsi, serta informasi social graph Facebook dan Twitter. Atribut lang HTML diatur dengan benar.','Enable Modules'=>'Aktifkan modul','Enable Add-on module